import React, { Component } from 'react';
import './headerstyle.css';
import NAV from './assets/navicon.png';

class Header extends Component{
    render(){
    return(
        <div>
        <nav>
        <h3>                    
        <ul>
            <li><a id="icon" href="#intro">[ICON]</a></li>
            <li><button id="button" onClick={this.classToggle}><img id="navicon"src={NAV}alt="" /></button></li>
            <span id = "hidden">     
            <li><a href="#experience">Experience and Projects</a></li>
            <li><a href="#awards">Skills/Awards</a></li>      
            <li><a href="#education">Education</a></li>      
            <li><a href="#contacts">Contacts</a></li>   </span>
        </ul>
        </h3>
        </nav>
        </div>
    );
}
classToggle(){
    if(document.getElementById('hidden').style.display === 'block'){
        document.getElementById('hidden').style.display = 'none';
    }
    else{
        document.getElementById('hidden').style.display = 'block';
    }
}
}
export default Header;